var n='\n~ input[type="range"] {\n    outline: none;\n    accent-color: var(--ok_fg-accent);\n    box-shadow: none;\n}\n\n/* Input / Textarea / Select */\n~ input:focus,\n    ~ select:focus,\n    ~ textarea:focus {\n    \n    box-shadow: 0 0 0 2px var(--ok_focus-ring);\n    outline: calc(var(--ok_space-xs)) solid var(--ok_fg-accent);\n}\n\n~ input[type="range"]:focus {\n    outline: none;\n    filter: brightness(1.2);\n    box-shadow: none;\n}\n\n~ input[type="range"]:focus::-webkit-slider-thumb {\n    box-shadow: 0 0 0 4px color-mix(in srgb, var(--ok_fg-accent) 50%, transparent);\n    background-clip: padding-box;\n    border: none;\n    border-radius: 50%;\n}\n\n~ input[type="range"]:focus::-moz-range-thumb {\n    box-shadow: 0 0 0 4px color-mix(in srgb, var(--ok_fg-accent) 50%, transparent);\n    background-clip: padding-box;\n    border: none;\n    border-radius: 50%;\n}\n\n~ input:disabled {\n    cursor:  not-allowed; \n}';export{n as default};
